mapper.select:
SELECT COUNT(*) FROM ( SELECT RE.REQORDERSTATUS AS REQORDERSTATUS , COALESCE(RE.ABLEREQORDERYN, I.POABLEYN) AS ABLEREQORDERYN , 'Y' AS URGENCYREQORDERYN , COALESCE(RE.SEQ, 1) AS SEQ , I.OWKEY , IC.CTKEY , (SELECT CTNM FROM TORDER_MST_CT WHERE CTKEY = RE.REQCTKEY) AS CTNM -- 상품정보 , I.ICKEY , I.ICNM , I.UNICYN , CASE I.ASRTYN WHEN 'Y' THEN '아소트' ELSE '일반' END AS ASRTYN , COALESCE(S_ICUT.IC_EA, 1) AS ICEA , COALESCE(S_ICUT.IC_CTN, 1) AS ICCTN , COALESCE(S_ICUT.IC_CPP, 1) AS ICCPP , COALESCE(S_ICUT.IC_CTN, 1) * COALESCE(S_ICUT.IC_CPP, 1) AS ICPLT , IC.LCKEY -- 발주구역 , LC.ANSUNGB2BPOCTG , LC.NAMSAB2BPOCTG , LC.BUSANB2BPOCTG
, CASE WHEN B2B_REQORDER.NAMSA_IBEXPCTDAY >= TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') THEN B2B_REQORDER.NAMSA_IBEXPCTQTY ELSE 0 END AS NAMSAIBEXPCTQTY , CASE WHEN B2B_REQORDER.BUSAN_IBEXPCTDAY >= TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') THEN B2B_REQORDER.BUSAN_IBEXPCTQTY ELSE 0 END AS BUSANIBEXPCTQTY , CASE WHEN B2B_REQORDER.ANSUNG_IBEXPCTDAY >= TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') THEN B2B_REQORDER.ANSUNG_IBEXPCTQTY ELSE 0 END AS ANSUNGIBEXPCTQTY
-- B2B 센터 재고 , COALESCE(B2B_REQORDER.NAMSA_AVQTY, 0) AS NAMSAAVQTY , COALESCE(B2B_REQORDER.BUSAN_AVQTY, 0) AS BUSANAVQTY , COALESCE(B2B_REQORDER.ANSUNG_AVQTY, 0) AS ANSUNGAVQTY -- B2B 일 평균 출고량 , COALESCE(B2B_REQORDER.NAMSA_AVGOBQTY, 0) AS NAMSAAVGOBQTY , COALESCE(B2B_REQORDER.BUSAN_AVGOBQTY, 0) AS BUSANAVGOBQTY , COALESCE(B2B_REQORDER.ANSUNG_AVGOBQTY, 0) AS ANSUNGAVGOBQTY -- B2B 센터 보장재고 , COALESCE(GRTDAYS.NAMSA_B2BCTGRTDAYS, 1) AS NAMSAB2BCTGRTDAYS -- 남사 보장재고일수 , COALESCE(GRTDAYS.BUSAN_B2BCTGRTDAYS, 1) AS BUSANB2BCTGRTDAYS -- 부산 보장재고일수 , COALESCE(GRTDAYS.ANSUNG_B2BCTGRTDAYS, 1) AS ANSUNGB2BCTGRTDAYS -- 안성 보장재고일수 -- 발주 가용일 산정 , COALESCE(RE.REQCTKEY, '05') AS REQCTKEY , COALESCE(RE.CTLEADTIME, CT.CTLEADTIME) AS CTLEADTIME , COALESCE(RE.AVDAYS, RO.NEEDDAYS) AS AVDAYS
-- 요청 CBM , ICUT.VOL * RE.REQORDERQTY AS REQCBM , I.SLPRC * RE.REQORDERQTY AS REQPRC , ICUT.VOL AS VOL , I.SLPRC AS SLPRC -- 로케이션 CAPA 정보 : 한번더 확인 필요
--발주요청 데이터 , RE.REQORDERUNIT -- 발주단위 , RE.DLVYREQORDERUNIT -- 배송용기단위 , RE.REQORDERQTY -- 발주요청수량 , RE.REQORDERDAY , RE.REQORDERAR , COALESCE(RE.REQORDERTYPE, COALESCE(RO.REQORDERTYPE, 03)) AS REQORDERTYPE -- 03 : 이고발주 , COALESCE(RE.REQORDEREXCEPTYN, 'N') AS REQORDEREXCEPTYN , COALESCE(B2C_OB.NISYN, 'N') AS NISYN , COALESCE(B2C_OB.NISQTY, 0) AS NISQTY , OBAVG.OBFROMDAY , OBAVG.OBTODAY , OBAVG.APLYDAYS , CNTRUNIT.REQORDERUNITCTN , CNTRUNIT.REQORDERUNITPLT , CNTRUNIT.REQORDERUNITINN , RE.INSERTDATE , RE.INSERTURKEY , RE.UPDATEDATE , RE.UPDATEURKEY FROM TORDER_MST_IC I INNER JOIN TORDER_MST_ICUTXTYPE ICUT ON I.OWKEY = ICUT.OWKEY AND I.ICKEY = ICUT.ICKEY AND ICUNITTYPE = 'EA' INNER JOIN TORDER_MST_ICXCT IC ON I.OWKEY = IC.OWKEY AND I.ICKEY = IC.ICKEY INNER JOIN TORDER_MST_CT CT ON IC.CTKEY = CT.CTKEY INNER JOIN ( SELECT ICKEY , OWKEY , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'EA' THEN ICUNITQTY END), 1) AS IC_EA , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN ICUNITQTY END), 1) AS IC_CTN , COALESCE(SUM(CASE WHEN ICUNITTYPE = 'CTN' THEN CASE CPP WHEN 0 THEN 1 ELSE CPP END END), 1) AS IC_CPP FROM TORDER_MST_ICUTXTYPE WHERE OWKEY = 'DAISO' GROUP BY ICKEY, OWKEY ) S_ICUT ON I.OWKEY = S_ICUT.OWKEY AND I.ICKEY = S_ICUT.ICKEY LEFT JOIN TORDER_MST_REQORDER RO ON IC.OWKEY = RO.OWKEY AND IC.CTKEY = RO.CTKEY AND IC.ICKEY = RO.ICKEY LEFT JOIN ( SELECT A.ICKEY -- AVQTY , MAX(CASE WHEN A.CTKEY = '01' THEN A.AVQTY END) AS NAMSA_AVQTY , MAX(CASE WHEN A.CTKEY = '04' THEN A.AVQTY END) AS BUSAN_AVQTY , MAX(CASE WHEN A.CTKEY = '05' THEN A.AVQTY END) AS ANSUNG_AVQTY
-- PREIBQTY , MAX(CASE WHEN A.CTKEY = '01' THEN A.PREIBQTY END) AS NAMSA_PREIBQTY , MAX(CASE WHEN A.CTKEY = '04' THEN A.PREIBQTY END) AS BUSAN_PREIBQTY , MAX(CASE WHEN A.CTKEY = '05' THEN A.PREIBQTY END) AS ANSUNG_PREIBQTY
-- IBEXPCTDAY , MAX(CASE WHEN A.CTKEY = '01' THEN A.IBEXPCTDAY END) AS NAMSA_IBEXPCTDAY , MAX(CASE WHEN A.CTKEY = '04' THEN A.IBEXPCTDAY END) AS BUSAN_IBEXPCTDAY , MAX(CASE WHEN A.CTKEY = '05' THEN A.IBEXPCTDAY END) AS ANSUNG_IBEXPCTDAY
-- IBEXPCTQTY , MAX(CASE WHEN A.CTKEY = '01' THEN A.IBEXPCTQTY END) AS NAMSA_IBEXPCTQTY , MAX(CASE WHEN A.CTKEY = '04' THEN A.IBEXPCTQTY END) AS BUSAN_IBEXPCTQTY , MAX(CASE WHEN A.CTKEY = '05' THEN A.IBEXPCTQTY END) AS ANSUNG_IBEXPCTQTY
-- AVGOBQTY , MAX(CASE WHEN A.CTKEY = '01' THEN A.AVGOBQTY END) AS NAMSA_AVGOBQTY , MAX(CASE WHEN A.CTKEY = '04' THEN A.AVGOBQTY END) AS BUSAN_AVGOBQTY , MAX(CASE WHEN A.CTKEY = '05' THEN A.AVGOBQTY END) AS ANSUNG_AVGOBQTY
FROM TORDER_INFO_B2BAVGOBQTY_REQORDER A INNER JOIN TORDER_MST_CT B ON A.CTKEY = B.CTKEY WHERE A.CRITDAY = TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') GROUP BY A.ICKEY ORDER BY A.ICKEY
) B2B_REQORDER ON I.ICKEY = B2B_REQORDER.ICKEY LEFT JOIN ( SELECT #{CTKEY} AS CTKEY , MAX(CASE WHEN A.CTKEY = '01' THEN GRTIVDAYS END) AS NAMSA_B2BCTGRTDAYS , MAX(CASE WHEN A.CTKEY = '04' THEN GRTIVDAYS END) AS BUSAN_B2BCTGRTDAYS , MAX(CASE WHEN A.CTKEY = '05' THEN GRTIVDAYS END) AS ANSUNG_B2BCTGRTDAYS FROM TORDER_MST_CT A )GRTDAYS ON IC.CTKEY = GRTDAYS.CTKEY LEFT JOIN ( SELECT H.OWKEY, D.ICKEY, SUM(COALESCE(EXPCTQTY, 0)) AS B2C_IB_QTY FROM TORDER_INFO_SO_HD H INNER JOIN TORDER_INFO_SO_DT D ON H.OWKEY = D.OWKEY AND H.SOHDKEY = D.SOHDKEY INNER JOIN TORDER_MST_ORTYPE O ON H.OWKEY = O.OWKEY AND H.ORDERTYPECD = O.ORDERTYPECD WHERE O.POCALINCYN = 'Y' AND H.DLVYEXPCTDAY = TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') GROUP BY H.OWKEY, D.ICKEY ) B2C_IB ON IC.OWKEY = B2C_IB.OWKEY AND IC.ICKEY = B2C_IB.ICKEY LEFT JOIN ( SELECT H.OWKEY, D.ICKEY, D.URGENCYREQYN AS NISYN, SUM(D.INITQTY) AS NISQTY FROM TORDER_INFO_SO_HD H INNER JOIN TORDER_INFO_SO_DT D ON H.OWKEY = D.OWKEY AND H.SOHDKEY = D.SOHDKEY INNER JOIN TORDER_MST_ORTYPE O ON H.OWKEY = O.OWKEY AND H.ORDERTYPECD = O.ORDERTYPECD WHERE O.OBYN = 'Y' AND D.URGENCYREQYN = 'Y' AND H.DLVYEXPCTDAY >= TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') GROUP BY H.OWKEY, D.ICKEY, D.URGENCYREQYN ) B2C_OB ON IC.OWKEY = B2C_OB.OWKEY AND IC.ICKEY = B2C_OB.ICKEY LEFT JOIN TORDER_INFO_REQORDERIV RIV ON IC.OWKEY = RIV.OWKEY AND IC.CTKEY = RIV.CTKEY AND IC.ICKEY = RIV.ICKEY LEFT JOIN TORDER_INFO_REQORDER RE ON IC.OWKEY = RE.OWKEY AND IC.CTKEY = RE.CTKEY AND IC.ICKEY = RE.ICKEY AND RE.REQORDERDAY = TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') AND RE.URGENCYREQORDERYN = 'Y' LEFT JOIN TORDER_MST_LC LC ON IC.CTKEY = LC.CTKEY AND IC.LCKEY = LC.LCKEY LEFT JOIN TORDER_MST_OBAVGQTY OBAVG ON IC.OWKEY = OBAVG.OWKEY AND IC.CTKEY = OBAVG.CTKEY AND IC.ICKEY = OBAVG.ICKEY LEFT JOIN ( SELECT OWKEY , CTKEY , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'CTN' THEN CRITSET END), 0) AS REQORDERUNITCTN , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'PLT' THEN CRITSET END), 0) AS REQORDERUNITPLT , COALESCE(MAX(CASE WHEN REQORDERUNIT = 'INN' THEN CRITSET END), 0) AS REQORDERUNITINN FROM TORDER_MST_REQORDER_CNTRUNIT WHERE DELYN = 'N' GROUP BY OWKEY, CTKEY ) CNTRUNIT ON IC.OWKEY = CNTRUNIT.OWKEY AND IC.CTKEY = CNTRUNIT.CTKEY WHERE I.POABLEYN = 'Y' AND RO.REQORDERTYPE = '03'
AND I.OWKEY = #{OWKEY}
AND IC.CTKEY = #{CTKEY}
AND IC.ICKEY IN
#{item}
AND RE.REQORDEREXCEPTYN = #{REQORDEREXCEPTYN}
) F WHERE 1 = 1
AND F.NISYN = #{NISYN}

mapper.insert:
		/* oms-po-UrgencyPoPlanReq-sql-oracle.xml - insertUrgencyPoPlanReq */
		INSERT INTO TORDER_INFO_REQORDER
		(
			  OWKEY
            , CTKEY
            , REQORDERDAY
            , ICKEY
            , REQORDERTYPE
            , URGENCYREQORDERYN
            , SEQ
            , ICTGT
            , REQORDERAR
            , REQORDERNO
            , REQORDERSTATUS
            , ABLEREQORDERYN
            , UNICYN
            , AVGOBQTY
            , AVGOBFROMDAY
            , AVGOBTODAY
            , AVGAPLYDAYS
            , AVQTY
            , IBEXPCTQTY
            , REQCTKEY
            , CALAVDAYS
            , DLVYREQORDERUNIT
            , REQORDERQTY
            , CNFRMREQORDERQTY
            , AVDAYS
            , REQORDERUNIT
            , CTLEADTIME
		    , IBEXPCTDAY
		    , REQORDEREXCEPTYN
		    , UPLOADYN
            , INSERTDATE
            , INSERTURKEY
            , UPDATEDATE
            , UPDATEURKEY
			)
		VALUES	(
			  #{owkey}
            , #{ctkey}
            , #{reqorderday}
            , #{ickey}
            , #{reqordertype}
            , #{urgencyreqorderyn}
            , #{seq}
            , #{ictgt}
            , #{reqorderar}
            , #{reqorderno}
            , #{reqorderstatus}
            , #{ablereqorderyn}
            , #{unicyn}
            , #{eadayavgobqty}
            , #{avgobfromday}
            , #{avgobtoday}
            , #{avgaplydays}
            , #{avqty}
            , #{b2cibqty}
            , #{reqctkey}
            , #{calavdays}
            , #{reqorderunit}
            , #{reqorderqty}
            , #{cnfrmreqorderqty}
            , #{avdays}
            , #{reqorderunit}
            , #{ctleadtime}
			, #{ibexpctday}
		    , #{reqorderexceptyn}
		    , 'N'
		    , #{sysdate}
		    , #{surkey}
		    , #{sysdate}
		    , #{surkey}
		)

mapper.update:
		/* oms-po-UrgencyPoPlanReq-sql-oracle.xml - updateUrgencyPoPlanReq */
		UPDATE TORDER_INFO_REQORDER
		   SET ICTGT            = #{ictgt}
             , REQORDERAR       = #{reqorderar}
             , REQORDERNO       = #{reqorderno}
             , REQORDERSTATUS   = #{reqorderstatus}
             , ABLEREQORDERYN   = #{ablereqorderyn}
             , UNICYN           = #{unicyn}
             , AVGOBQTY         = #{eadayavgobqty}
             , AVGOBFROMDAY     = #{avgobfromday}
             , AVGOBTODAY       = #{avgobtoday}
             , AVGAPLYDAYS      = #{avgaplydays}
             , AVQTY            = #{avqty}
             , IBEXPCTQTY       = #{b2cibqty}
             , REQCTKEY         = #{reqctkey}
             , CALAVDAYS        = #{calavdays}
             , DLVYREQORDERUNIT = #{reqorderunit}
             , REQORDERQTY      = #{reqorderqty}
             , CNFRMREQORDERQTY = #{cnfrmreqorderqty}
             , AVDAYS           = #{avdays}
             , REQORDERUNIT     = #{reqorderunit}
             , CTLEADTIME       = #{CTLEADTIME}
             , UPDATEDATE       = #{sysdate}
             , UPDATEURKEY      = #{surkey}
		WHERE OWKEY             = #{owkey}
	      AND CTKEY             = #{ctkey}
	      AND REQORDERDAY       = #{reqorderday}
          AND ICKEY             = #{ickey}
          AND REQORDERTYPE      = #{reqordertype}
          AND URGENCYREQORDERYN = #{urgencyreqorderyn}
          AND SEQ               = #{seq}

		/* oms-po-UrgencyPoPlanReq-sql-oracle.xml - updateUrgencyReqprcs */
		UPDATE TORDER_INFO_SO_DT
		   SET URGENCYREQPRCSSEQ = #{reqorderno}
		WHERE OWKEY   = #{owkey}
	      AND SOHDKEY = #{sohdkey}
	      AND SODTKEY = #{sodtkey}
          AND ICKEY   = #{ickey}

mapper.select:
		SELECT COUNT(*)
		FROM TORDER_INFO_REQORDER
		WHERE REQORDERDAY = TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd')
		  AND URGENCYREQORDERYN = 'Y'
		  AND OWKEY    = #{owkey}
	      AND CTKEY    = #{ctkey}
	      AND ICKEY    = #{ickey}
          AND REQCTKEY = #{reqctkey}
